package com.google.gson;
import com.google.gson.internal.Streams;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import java.io.StringWriter;
import java.math.BigDecimal;
import java.math.BigInteger;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonElement;
import com.google.gson.JsonObject;
import org.junit.jupiter.api.Test;

class JsonElementTest {

  @Test
  void getAsJsonObject_whenIsJsonObjectTrue_returnsThisCastToJsonObject() {
    JsonElement jsonElement = mock(JsonElement.class, withSettings().defaultAnswer(CALLS_REAL_METHODS));
    when(jsonElement.isJsonObject()).thenReturn(true);
    // Cast to JsonObject to simulate the actual return type
    JsonObject jsonObject = mock(JsonObject.class);
    // When cast, return the mocked JsonObject
    // Since jsonElement is mocked, cast works as expected in test context
    // Override toString so exception message is meaningful if needed
    when(jsonElement.toString()).thenReturn("{\"mocked\":true}");

    // Use spy to allow casting this mock to JsonObject
    JsonElement spyElement = spy(jsonObject);
    doReturn(true).when(spyElement).isJsonObject();

    JsonObject result = spyElement.getAsJsonObject();
    assertSame(spyElement, result);
  }

  @Test
  void getAsJsonObject_whenIsJsonObjectFalse_throwsIllegalStateException() {
    JsonElement jsonElement = mock(JsonElement.class, withSettings().defaultAnswer(CALLS_REAL_METHODS));
    when(jsonElement.isJsonObject()).thenReturn(false);
    when(jsonElement.toString()).thenReturn("jsonElementToString");

    IllegalStateException exception = assertThrows(IllegalStateException.class, jsonElement::getAsJsonObject);
    assertEquals("Not a JSON Object: jsonElementToString", exception.getMessage());
  }
}
